import type { Card, NewCard, Review, Rating, DeckStat, Deck, NewDeck } from '@motivation/shared';
import { API_URL } from '../config.js';

export type { DeckStat };

export class VietnameseService {
    private static async request<T>(path: string, init?: RequestInit): Promise<T> {
        const response = await fetch(`${API_URL}${path}`, init);

        if (!response.ok) {
            const data = await response.json().catch(() => ({}));
            throw new Error(data.error ?? response.statusText ?? 'Request failed');
        }

        if (response.status === 204) {
            return undefined as T;
        }

        return response.json() as Promise<T>;
    }

    /**
     * Fetch FSRS cards that are due for review.
     * @param limit maximum number of cards to fetch
     * @returns list of cards ready to be reviewed
     */
    static async getDueReviewCards(limit: number = 20): Promise<Card[]> {
        return this.request<Card[]>(`/api/sections/vietnamese/review?limit=${limit}`);
    }

    static async getDeckStats(): Promise<DeckStat[]> {
        return this.request<DeckStat[]>('/api/sections/vietnamese/decks/stats');
    }

    static async getDecks(): Promise<Deck[]> {
        return this.request<Deck[]>('/api/sections/vietnamese/decks');
    }

    static async createDeck(payload: Pick<NewDeck, 'name' | 'description'>): Promise<Deck> {
        return this.request<Deck>('/api/sections/vietnamese/decks', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
    }

    static async updateDeck(id: string, payload: Partial<Pick<Deck, 'name' | 'description'>>): Promise<Deck> {
        return this.request<Deck>(`/api/sections/vietnamese/decks/${id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
    }

    static async deleteDeck(id: string): Promise<void> {
        await this.request<void>(`/api/sections/vietnamese/decks/${id}`, { method: 'DELETE' });
    }

    static async getCardsByDeck(deckId: string): Promise<Card[]> {
        return this.request<Card[]>(`/api/sections/vietnamese/decks/${deckId}/cards`);
    }

    static async createCard(deckId: string, payload: Pick<NewCard, 'front' | 'back' | 'notes'>): Promise<Card> {
        return this.request<Card>(`/api/sections/vietnamese/decks/${deckId}/cards`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
    }

    static async updateCard(id: string, payload: Partial<Pick<Card, 'front' | 'back' | 'notes'>>): Promise<Card> {
        return this.request<Card>(`/api/sections/vietnamese/cards/${id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload),
        });
    }

    static async uploadCardAudio(id: string, file: File): Promise<Card> {
        const formData = new FormData();
        formData.append('audio', file);
        return this.request<Card>(`/api/sections/vietnamese/cards/${id}/audio`, {
            method: 'PUT',
            body: formData,
        });
    }

    static async deleteCardAudio(id: string): Promise<Card> {
        return this.request<Card>(`/api/sections/vietnamese/cards/${id}/audio`, {
            method: 'DELETE',
        });
    }

    static async deleteCard(id: string): Promise<void> {
        await this.request<void>(`/api/sections/vietnamese/cards/${id}`, { method: 'DELETE' });
    }

    /**
     * Submit a rating (1-4) for a flashcard to update its FSRS scheduling.
     * @param cardId the ID of the card being reviewed
     * @param rating the score given (1=Again, 2=Hard, 3=Good, 4=Easy)
     * @returns the updated review state
     */
    static async submitReview(cardId: string, rating: Rating): Promise<Review> {
        return this.request<Review>('/api/sections/vietnamese/review', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ card_id: cardId, rating }),
        });
    }
}
